import React, { useEffect, useState } from 'react'
import { useLocation } from 'react-router-dom'
import axios from 'axios'

export default function PrintMovimentacoes() {
  const { state: filters } = useLocation()
  const [lista, setLista] = useState([])

  useEffect(() => {
    // Ajuste este endpoint para aceitar os filtros via query params:
    axios.get('/api/movimentacoes', { params: filters })
      .then(res => setLista(res.data))
      .catch(console.error)
  }, [filters])

  useEffect(() => {
    if (lista.length) window.print()
  }, [lista])

  return (
    <div className="p-4">
      <h1 className="text-xl mb-4">Movimentações Filtradas</h1>
      <table className="w-full border-collapse">
        <thead>
          <tr>
            <th className="border px-2 py-1">Tipo</th>
            <th className="border px-2 py-1">Caixa</th>
            <th className="border px-2 py-1">Aluno</th>
            <th className="border px-2 py-1">Período</th>
            <th className="border px-2 py-1">Data</th>
            <th className="border px-2 py-1">Operador</th>
          </tr>
        </thead>
        <tbody>
          {lista.map(m => (
            <tr key={m.id}>
              <td className="border px-2 py-1">{m.tipo}</td>
              <td className="border px-2 py-1">{m.caixaNome}</td>
              <td className="border px-2 py-1">{m.alunoNome}</td>
              <td className="border px-2 py-1">{m.periodoNome}</td>
              <td className="border px-2 py-1">{m.criado_em}</td>
              <td className="border px-2 py-1">{m.operadorNome}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  )
}
